const input = $input.all();

const urlsSet = new Set();

for (const item of input) {
  const raw =
    item.json.text ||
    item.json.output ||
    item.json.response ||
    "";

  if (!raw) continue;

  const lines = raw.split(/\r?\n/);

  for (const line of lines) {
    const url = line.trim();

    if (url && url.startsWith("http")) {
      urlsSet.add(url);
    }
  }
}

const urls = Array.from(urlsSet);

const result = {};

urls.forEach((url, i) => {
  result[`output${i + 1}`] = url;
});

return [{ json: result }];

