// Get raw HTML from previous node
const html = $input.first().json.data || "";

// -------- CLEAN HTML --------
function cleanHTML(html) {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, '')
    .replace(/<iframe[\s\S]*?<\/iframe>/gi, '')
    .replace(/<svg[\s\S]*?<\/svg>/gi, '')
    .replace(/<[^>]+>/g, ' ') // remove all tags
    .replace(/\s+/g, ' ')
    .trim();
}

// -------- EXTRACT SPECIFIC DATA --------
function extractBetween(html, tag) {
  const regex = new RegExp(`<${tag}[^>]*>(.*?)<\\/${tag}>`, "i");
  const match = html.match(regex);
  return match ? match[1].replace(/<[^>]+>/g, '').trim() : "";
}

// Title
const title = extractBetween(html, "title");

// Meta description
const metaDescMatch = html.match(/<meta\s+name=["']description["']\s+content=["'](.*?)["']/i);
const metaDescription = metaDescMatch ? metaDescMatch[1] : "";

// Headings (H1, H2)
const h1Matches = [...html.matchAll(/<h1[^>]*>(.*?)<\/h1>/gi)].map(m => m[1].replace(/<[^>]+>/g, '').trim());
const h2Matches = [...html.matchAll(/<h2[^>]*>(.*?)<\/h2>/gi)].map(m => m[1].replace(/<[^>]+>/g, '').trim());

// -------- MAIN TEXT CLEANING --------
let cleanedText = cleanHTML(html);

// 🔥 LIMIT SIZE (VERY IMPORTANT)
const MAX_LENGTH = 8000;
if (cleanedText.length > MAX_LENGTH) {
  cleanedText = cleanedText.substring(0, MAX_LENGTH);
}

// -------- RETURN STRUCTURED OUTPUT --------
return [
  {
    json: {
      title,
      metaDescription,
      headings: {
        h1: h1Matches.slice(0, 5),
        h2: h2Matches.slice(0, 10),
      },
      content: cleanedText
    }
  }
];

